import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Safety/webdav-site-access.md","filePath":"hi/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"hi/Safety/webdav-site-access.md"};function o(r,e,c,p,h,b){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>Security Settings में WebDAV setting आपके ImgBed site को WebDAV endpoint के रूप में उपलब्ध कराती है।</p><p>Enable करने के बाद आप Windows, macOS, mobile file managers या किसी भी WebDAV-compatible client से ImgBed files को remote folder की तरह browse, upload, delete और manage कर सकते हैं।</p><p>यह site का WebDAV access entry है। यह Upload Settings वाले WebDAV storage channel से अलग है। Upload channel files को third-party WebDAV service में store करता है। यह setting आपके ImgBed site को clients के लिए WebDAV access provide करने देती है।</p><h2 id="कहाँ-सेट-करें" tabindex="-1">कहाँ सेट करें <a class="header-anchor" href="#कहाँ-सेट-करें" aria-label="Permalink to &quot;कहाँ सेट करें&quot;">​</a></h2><p>Admin panel खोलें, फिर यहाँ जाएँ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="यह-feature-क्या-करता-है" tabindex="-1">यह Feature क्या करता है <a class="header-anchor" href="#यह-feature-क्या-करता-है" aria-label="Permalink to &quot;यह Feature क्या करता है&quot;">​</a></h2><p>WebDAV enabled होने के बाद ImgBed एक fixed access URL provide करता है:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>अपने ImgBed file directory से connect करने के लिए यही URL इस्तेमाल करें।</p><p>अच्छे use cases:</p><ul><li>Computer file manager से ImgBed files सीधे browse करें।</li><li>Images को WebDAV folder में drag करके upload करें।</li><li>Local file manager से ImgBed folders organize करें।</li><li>WebDAV-compatible software से images sync या manage करें।</li><li>Admin panel खोले बिना ImgBed content access करें।</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>WebDAV endpoint चालू करता है।</p><p>Disabled होने पर clients WebDAV के ज़रिए connect नहीं कर सकते।</p><h3 id="username-और-password" tabindex="-1">Username और Password <a class="header-anchor" href="#username-और-password" aria-label="Permalink to &quot;Username और Password&quot;">​</a></h3><p>Clients WebDAV से connect करते समय ये credentials इस्तेमाल करते हैं।</p><p>Dedicated WebDAV username और password इस्तेमाल करें। Admin password या upload password reuse न करें।</p><p>अगर username या password में से कोई भी खाली है, तो WebDAV clients ठीक से connect नहीं कर पाएँगे।</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode तय करता है कि images पढ़ते समय WebDAV clients कौन सा image URL prefer करें।</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed context के आधार पर चुनता है। Normal use के लिए recommended।</td></tr><tr><td>Original</td><td>Original images prefer करता है।</td></tr><tr><td>Thumbnail</td><td>Thumbnails prefer करता है। Fast preview के लिए useful।</td></tr></tbody></table><p>अगर आप unsure हैं, तो <code>Smart loading</code> रखें।</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel WebDAV uploads के लिए इस्तेमाल होता है।</p><p>जब आप Windows या किसी दूसरे client से WebDAV directory में files copy करते हैं, तो ImgBed उन्हें selected default upload channel के ज़रिए upload करता है।</p><p>अगर default channel selected नहीं है, तो browsing काम कर सकती है, लेकिन uploads fail हो सकते हैं।</p><h2 id="windows-11-में-webdav-access-करना" tabindex="-1">Windows 11 में WebDAV Access करना <a class="header-anchor" href="#windows-11-में-webdav-access-करना" aria-label="Permalink to &quot;Windows 11 में WebDAV Access करना&quot;">​</a></h2><p>Windows 11 WebDAV को network location के रूप में add कर सकता है।</p><ol><li><code>This PC</code> खोलें।</li><li><code>Add a network location</code> चुनें।</li><li><code>https://your-domain.com/dav</code> डालें।</li><li>Prompt आने पर अपना WebDAV username और password डालें।</li><li>Wizard finish करें। इसके बाद WebDAV directory File Explorer में खुल सकेगी।</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>Add होने के बाद WebDAV directory Windows File Explorer में दिखती है। आप normal folder की तरह files open, copy और manage कर सकते हैं।</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>Successful WebDAV connection के बाद आप आम तौर पर ये कर सकते हैं:</p><ul><li>Files और folders देखें।</li><li>Files upload करें।</li><li>Folders create करें।</li><li>Files या folders rename करें।</li><li>Files move करें।</li><li>Files delete करें।</li></ul><p>WebDAV रोज़मर्रा के access और छोटे file management के लिए बेहतर है। बड़े moves, bulk deletes या complex organization के लिए admin panel इस्तेमाल करें।</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Successful WebDAV connections Login Device Management के WebDAV tab में भी दिखते हैं।</p><p>आप वहाँ WebDAV clients review कर सकते हैं और ज़रूरत पड़ने पर पुराने devices force offline कर सकते हैं।</p><p>अगर आप WebDAV username या password बदलते हैं, तो पुराने clients को फिर से sign in करना होगा।</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-बार-बार-username-और-password-क्यों-पूछ-रहा-है" tabindex="-1">Windows बार-बार Username और Password क्यों पूछ रहा है? <a class="header-anchor" href="#windows-बार-बार-username-और-password-क्यों-पूछ-रहा-है" aria-label="Permalink to &quot;Windows बार-बार Username और Password क्यों पूछ रहा है?&quot;">​</a></h3><p>जाँचें:</p><ul><li>URL <code>https://your-domain.com/dav</code> है।</li><li>Username और password WebDAV settings से match करते हैं।</li><li>WebDAV enabled है।</li><li>Site HTTPS पर accessible है।</li></ul><h3 id="browsing-चल-रही-है-लेकिन-upload-fail-हो-रहा-है" tabindex="-1">Browsing चल रही है, लेकिन Upload fail हो रहा है <a class="header-anchor" href="#browsing-चल-रही-है-लेकिन-upload-fail-हो-रहा-है" aria-label="Permalink to &quot;Browsing चल रही है, लेकिन Upload fail हो रहा है&quot;">​</a></h3><p><code>Default channel</code> check करें।</p><p>WebDAV uploads को default upload channel चाहिए। अगर वह missing, disabled या misconfigured है, तो uploads fail हो सकते हैं।</p><h3 id="access-speed-unstable-है" tabindex="-1">Access Speed unstable है <a class="header-anchor" href="#access-speed-unstable-है" aria-label="Permalink to &quot;Access Speed unstable है&quot;">​</a></h3><p>WebDAV performance client, network, file count और default upload channel पर depend करती है।</p><p>अगर किसी directory में बहुत files हैं, तो उन्हें एक ही directory में रखने के बजाय folders में organize करें।</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>WebDAV access के लिए HTTPS इस्तेमाल करें।</li><li>Strong password set करें।</li><li>WebDAV password untrusted लोगों से share न करें।</li><li>इस्तेमाल न कर रहे हों तो WebDAV बंद रखें।</li><li>Login Device Management में unused WebDAV devices periodically clean up करें।</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients browser upload page वाले large-file chunking flow का इस्तेमाल नहीं करते। नीचे दिए गए suggested limits से बड़ी files के लिए web upload page इस्तेमाल करें।</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(n,[["render",o]]);export{m as __pageData,f as default};
